const socket = io();

const messages = document.getElementById('messages');
const form = document.getElementById('message-form');
const input = document.getElementById('message-input');

let myUsername = 'Anonymous'; // Will be set by the server

// Function to append messages to the chat window
function appendMessage(user, msg, isSelf = false, isSystem = false) {
    const item = document.createElement('div');
    item.classList.add('message');

    if (isSystem) {
        item.classList.add('system');
        item.textContent = msg;
    } else {
        const userSpan = document.createElement('strong');
        userSpan.textContent = user;
        item.appendChild(userSpan);
        item.appendChild(document.createTextNode(msg));

        if (isSelf) {
            item.classList.add('self');
        } else {
            item.classList.add('other');
        }
    }

    messages.appendChild(item);
    messages.scrollTop = messages.scrollHeight; // Scroll to bottom
}

// Listen for 'set username' event from the server
socket.on('set username', (username) => {
    myUsername = username;
    console.log(`My anonymous username is: ${myUsername}`);
});

// Handle form submission
form.addEventListener('submit', (e) => {
    e.preventDefault(); // Prevent page reload
    if (input.value) {
        socket.emit('chat message', input.value);
        input.value = ''; // Clear the input field
    }
});

// Listen for 'chat message' events from the server
socket.on('chat message', (data) => {
    const { user, message } = data;
    const isSelf = (user === myUsername);
    const isSystem = (user === 'System');
    appendMessage(user, message, isSelf, isSystem);
});
